// Recibimos el número de unidades desde el Agente
const unidades = $input.first().json.unidades || 1; 

// ACTUALIZACIÓN DE TARIFA VIGENTE ZMG 2026
const tarifaOficial = 11.00; 

const total = unidades * tarifaOficial;

return {
  costo_total: total.toFixed(2),
  moneda: "MXN",
  detalle: `Tarifa actualizada: ${unidades} unidad(es) a $11.00 c/u`
};
